include  <p>/*   ====================== 硬件连接说明（Arduino Mega2560）======================   I2C SDA -&gt; D20   I2C SCL -&gt; D21   电机方向 DIR -&gt; D8   电机使能 EN(PWM) -&gt; D9   （PWM 控制电机速度/力矩，0~255）   编码器 A -&gt; D2   编码器 B -&gt; D3   ===========================================================================</p> <p>本程序目标：   1) 读取温度传感器（MPL3115A2）的温度 T   2) 把温度映射到“指针轴预期角度 expectedDeg”   3) 通过编码器读数得到“指针轴实际角度 actualDeg”   4) GO 模式下：电机自动转动，使 actualDeg 逼近 expectedDeg   5) STOP 模式下：电机不动（即使温度变化也不跟随）   6) 串口命令：      s：STOP（停止跟随、停止电机）      g：GO（开始跟随温度）      r / l：驱动轮转 1 圈（±12 count）      r5 / l5：驱动轮转 5 圈（±60 count）      sync：校准（把当前指针所指位置当成“正确位置”，修正 offset） */</p> <p>// ---------------- 引脚定义 ---------------- const uint8_t PIN_DIR   = 8;   // 电机方向 const uint8_t PIN_EN    = 9;   // 电机使能（PWM） const uint8_t PIN_ENC_A = 2;   // 编码器 A const uint8_t PIN_ENC_B = 3;   // 编码器 B</p> <p>// ---------------- 方向反转选项 ---------------- // 如果你发现： // - r 指令实际向左转，或 GO 跟随方向相反 // 可以通过修改这两个布尔值快速修正方向，不用重新接线 const bool INVERT_MOTOR_DIR = true;  // 反转电机方向信号 const bool INVERT_ENCODER   = true;  // 反转编码器计数方向（count 正负）</p> <p>// ---------------- 机械参数（很关键） ---------------- // 实测：驱动轮转 1 圈，编码器 count 变化为 12 const long  ONE_REV_COUNTS = 12;</p> <p>// 减速比：驱动轮转 GEAR_RATIO 圈，指针轴转 1 圈 // drive : shaft = 52.734 : 1 const float GEAR_RATIO = 52.734f;</p> <p>/   degPerDriveCountOnShaft():   计算“驱动轮编码器每增加 1 count，指针轴转过多少度”   推导：   - 驱动轮 1 圈 = 12 count   - 驱动轮转 52.734 圈，指针轴转 360°   因此：   1 count 对应的指针轴角度 = 360 / (12 * 52.734) / static inline float degPerDriveCountOnShaft() {   return 360.0f / (float)ONE_REV_COUNTS / GEAR_RATIO; }</p> <p>/   wrap180(a):   把任意角度归一化到 (-180, 180] 区间   角度是周期量，例如：   190° 等价于 -170°   540° 等价于 180°   归一化的目的：   - 避免角度计算越界   - 避免控制器走“绕大圈”的路径 / static inline float wrap180(float a) {   while (a &gt; 180.0f) a -= 360.0f;   while (a &lt;= -180.0f) a += 360.0f;   return a; }</p> <p>/   shaftDegToDriveCount(deg):   把“指针轴角度(°)”换算成“驱动轮编码器 count”   注意：这里只做纯比例换算，不包含校准 offset（offset 在别处处理） / static inline long shaftDegToDriveCount(float deg) {   return lroundf(deg / degPerDriveCountOnShaft()); }</p> <p>/   driveCountToShaftDeg(countDrive, calibOffsetDeg):   把“驱动轮编码器 count”换算成“指针轴角度(°)”，并加上校准偏移 calibOffsetDeg   模型：   actualDeg = count * (degPerCount) + calibOffsetDeg   再 wrap180 折回到 (-180,180] 区间 / static inline float driveCountToShaftDeg(long countDrive, float calibOffsetDeg) {   return wrap180((float)countDrive * degPerDriveCountOnShaft() + calibOffsetDeg); }</p> <p>// ---------------- 温度传感器（MPL3115A2）I2C 部分 ---------------- // MPL3115A2 常用 I2C 地址 0x60 const uint8_t MPL3115A2_ADDR = 0x60;</p> <p>/   i2cWrite8(addr, reg, val):   向 I2C 设备的 reg 寄存器写入 1 个字节 val   返回 true 表示写入成功 / bool i2cWrite8(uint8_t addr, uint8_t reg, uint8_t val) {   Wire.beginTransmission(addr);   Wire.write(reg);   Wire.write(val);   return (Wire.endTransmission() == 0); }</p> <p>/   i2cReadBytes(addr, reg, buf, len):   从 I2C 设备的 reg 寄存器开始，连续读取 len 个字节，放入 buf   返回 true 表示读取成功 / bool i2cReadBytes(uint8_t addr, uint8_t reg, uint8_t* buf, uint8_t len) {   Wire.beginTransmission(addr);   Wire.write(reg);   // endTransmission(false) = 不释放总线（重复启动），适合“先写寄存器地址再读数据”   if (Wire.endTransmission(false) != 0) return false;</p> <p>uint8_t got = Wire.requestFrom(addr, len);   if (got != len) return false;</p> <p>for (uint8_t i = 0; i &lt; len; i++) buf[i] = Wire.read();   return true; }</p> <p>/   mpl3115a2Init():   初始化 MPL3115A2 使其进入温度测量模式   - PT_DATA_CFG(0x13) 写 0x07：使能事件标志等功能   - CTRL_REG1(0x26) 写 0xB9：设置过采样并置为 Active（开始测量） / bool mpl3115a2Init() {   if (!i2cWrite8(MPL3115A2_ADDR, 0x13, 0x07)) return false;   if (!i2cWrite8(MPL3115A2_ADDR, 0x26, 0xB9)) return false;   delay(10);   return true; }</p> <p>/   readTemperatureC(tempC):   读取温度，返回摄氏度 float   MPL3115A2 温度寄存器从 0x04 开始：   - buf[0] = 温度整数部分（有符号）   - buf[1] 高 4 位为小数（单位 1/16°C） / bool readTemperatureC(float &amp;tempC) {   uint8_t buf[2];   if (!i2cReadBytes(MPL3115A2_ADDR, 0x04, buf, 2)) return false;</p> <p>int8_t msb = (int8_t)buf[0];   uint8_t lsb = buf[1];</p> <p>float frac = (float)(lsb &gt;&gt; 4) / 16.0f;      // 4bit 小数   tempC = (float)msb + ((msb &gt;= 0) ? frac : -frac);   return true; }</p> <p>// ---------------- 温度 -&gt; 预期角度 映射 ---------------- // 温度量程：20~30 °C const float TEMP_MIN = 20.0f; const float TEMP_MAX = 30.0f;</p> <p>// 对应角度量程：-120~+120 °（指针轴角度） const float ANGLE_MIN = -120.0f; const float ANGLE_MAX =  120.0f;</p> <p>/   tempToAngleDeg(t):   把温度 t（°C）线性映射到指针轴角度（°）   - 温度低于 TEMP_MIN：夹到 TEMP_MIN   - 温度高于 TEMP_MAX：夹到 TEMP_MAX   映射公式：   a = ANGLE_MIN + (t - TEMP_MIN) * (ANGLE_MAX - ANGLE_MIN)/(TEMP_MAX - TEMP_MIN) / static inline float tempToAngleDeg(float t) {   if (t &lt; TEMP_MIN) t = TEMP_MIN;   if (t &gt; TEMP_MAX) t = TEMP_MAX;</p> <p>float a = ANGLE_MIN + (t - TEMP_MIN) * (ANGLE_MAX - ANGLE_MIN) / (TEMP_MAX - TEMP_MIN);   return wrap180(a); }</p> <p>// ---------------- 电机控制函数 ----------------</p> <p>/   stopMotor():   让 PWM=0，电机停止（断电）   注意：这是“滑行停”，不是刹车 / void stopMotor() { analogWrite(PIN_EN, 0); }</p> <p>/   setMotor(dirHigh, pwm):   设置电机方向和 PWM 输出   - dirHigh: 逻辑方向（true/false）   - pwm: 0~255   INVERT_MOTOR_DIR 可以用来反转方向 / void setMotor(bool dirHigh, int pwm) {   if (INVERT_MOTOR_DIR) dirHigh = !dirHigh;   digitalWrite(PIN_DIR, dirHigh ? HIGH : LOW);   analogWrite(PIN_EN, pwm); }</p> <p>// ---------------- 编码器对象与读取 ---------------- Encoder enc(PIN_ENC_A, PIN_ENC_B);</p> <p>/   readCountDrive():   读取编码器计数（驱动轮侧）   INVERT_ENCODER 用于反转 count 正负 / long readCountDrive() {   long c = enc.read();   if (INVERT_ENCODER) c = -c;   return c; }</p> <p>// ---------------- 运动控制器（你验证“十分完美”的部分） ---------------- /*   控制思想：分两段   1) COARSE（粗调）：用比例控制 P，把误差快速拉近（连续输出 PWM）   2) NUDGE（微调）：靠短脉冲一点点推，尽量落到 err=0（并在脉冲间等待停稳）</p> <p>zones:   FAR_ZONE: 误差很大 -&gt; 快档粗调   FINE_ZONE: 误差很小 -&gt; 进入微调（nudge） */ const long FAR_ZONE  = 8; const long NEAR_ZONE = 3; // 此版本中主要用于概念，实际判断用 FAR_ZONE/FINE_ZONE const long FINE_ZONE = 2;</p> <p>// 稳定判定： // err==0 连续 500ms -&gt; 认为到位 // err==±1 连续 800ms -&gt; 可选兜底（允许少量误差） const long TOL_DONE = 0; const unsigned long STABLE_MS_ZERO = 500; const unsigned long STABLE_MS_ONE  = 800; const bool ALLOW_FALLBACK_PLUSMINUS1 = true;</p> <p>// 粗调比例系数（P 控制） const float KP_COARSE = 7.0f;</p> <p>// PWM 限幅：保证“能动 + 不过猛” const int PWM_COARSE_MIN_FAST = 60; const int PWM_COARSE_MAX_FAST = 130;</p> <p>const int PWM_COARSE_MIN_SLOW = 55; const int PWM_COARSE_MAX_SLOW = 100;</p> <p>// 微调 nudge：靠短脉冲推一下，然后等待 const int PWM_NUDGE = 55; const unsigned long NUDGE_OFF_MS = 160;     // 脉冲之间等待停稳（很关键） const unsigned long NUDGE_ON_MS_COARSE = 35; // err=2 时脉冲稍长 const unsigned long NUDGE_ON_MS_FINE   = 15; // err=1 时脉冲更短，争取落到 0</p> <p>// 调度周期/打印周期/超时保护 const unsigned long CTRL_MS   = 10;   // 控制周期 10ms const unsigned long PRINT_MS  = 200;  // 串口打印周期 200ms const unsigned long TIMEOUT_MS = 7000;</p> <p>// 运动状态机 enum MotionState { M_IDLE, M_COARSE_FAST, M_COARSE_SLOW, M_NUDGE_OFF, M_NUDGE_ON }; MotionState mstate = M_IDLE;</p> <p>// 运动目标（驱动轮编码器 count） long targetCountDrive = 0;</p> <p>// 运动开始时间，用于超时 unsigned long moveStartMs = 0;</p> <p>// nudge 相位起始时间 unsigned long phaseT0 = 0;</p> <p>// 用于稳定判定的计时器 unsigned long stableZeroT0 = 0; unsigned long stableOneT0  = 0;</p> <p>/   motionStartTo(newTargetCount):   启动一次运动，让编码器 count 走到 newTargetCount / void motionStartTo(long newTargetCount) {   targetCountDrive = newTargetCount;   moveStartMs = millis();   stableZeroT0 = 0;   stableOneT0  = 0;   mstate = M_COARSE_FAST; }</p> <p>/   motionMoveBy(delta):   相对运动：在当前 count 基础上 +delta   用于 r/l/r5/l5 命令 / void motionMoveBy(long delta) {   long c = readCountDrive();   motionStartTo(c + delta); }</p> <p>/   motionUpdate():   运动控制器核心状态机   每 CTRL_MS 调用一次：   - 计算 err   - 粗调 / 微调   - 输出 PWM   - 到位后进入 IDLE / void motionUpdate() {   unsigned long now = millis();</p> <p>long c = readCountDrive();   long err = targetCountDrive - c;   long aerr = labs(err);</p> <p>// 1) 超时保护：防止编码器失效一直转   if (mstate != M_IDLE &amp;&amp; now - moveStartMs &gt; TIMEOUT_MS) {     mstate = M_IDLE;     stopMotor();   }</p> <p>// 2) 稳定判定：err==0 或 err==±1 持续一定时间，认为到位   if (mstate != M_IDLE) {     if (err == 0) {       if (stableZeroT0 == 0) stableZeroT0 = now;     } else {       stableZeroT0 = 0;     }</p> <pre><code>if (labs(err) == 1) {
  if (stableOneT0 == 0) stableOneT0 = now;
} else {
  stableOneT0 = 0;
}

if (TOL_DONE == 0) {
  if (stableZeroT0 != 0 &amp;&amp; now - stableZeroT0 &gt;= STABLE_MS_ZERO) {
    mstate = M_IDLE; stopMotor();
  } else if (ALLOW_FALLBACK_PLUSMINUS1 &amp;&amp; stableOneT0 != 0 &amp;&amp; now - stableOneT0 &gt;= STABLE_MS_ONE) {
    mstate = M_IDLE; stopMotor();
  }
}
</code></pre> <p>}</p> <p>// 3) 状态机输出   if (mstate == M_IDLE) {     stopMotor();     return;   }</p> <p>// ---- 粗调阶段：连续 PWM，快速逼近 ----   if (mstate == M_COARSE_FAST || mstate == M_COARSE_SLOW) {</p> <pre><code>// 误差很小 -&gt; 进入微调
if (aerr &lt;= FINE_ZONE) {
  mstate = M_NUDGE_OFF;
  phaseT0 = now;
  stopMotor();
}
// 误差中等 -&gt; 慢档粗调
else if (aerr &lt; FAR_ZONE) {
  mstate = M_COARSE_SLOW;
}
// 误差很大 -&gt; 快档粗调
else {
  mstate = M_COARSE_FAST;
}

// 在粗调状态下：计算 P 控制输出 u=Kp*err，并转成 PWM
if (mstate == M_COARSE_FAST || mstate == M_COARSE_SLOW) {
  float u = KP_COARSE * (float)err;
  bool dirHigh = (u &gt;= 0);
  int pwm = (int)fabs(u);

  // PWM 限幅：确保能动、避免过猛
  if (mstate == M_COARSE_FAST) {
    if (pwm &gt; PWM_COARSE_MAX_FAST) pwm = PWM_COARSE_MAX_FAST;
    if (pwm &gt; 0 &amp;&amp; pwm &lt; PWM_COARSE_MIN_FAST) pwm = PWM_COARSE_MIN_FAST;
  } else {
    if (pwm &gt; PWM_COARSE_MAX_SLOW) pwm = PWM_COARSE_MAX_SLOW;
    if (pwm &gt; 0 &amp;&amp; pwm &lt; PWM_COARSE_MIN_SLOW) pwm = PWM_COARSE_MIN_SLOW;
  }

  setMotor(dirHigh, pwm);
}
</code></pre> <p>}</p> <p>// ---- 微调阶段：OFF 等待 ----   else if (mstate == M_NUDGE_OFF) {     stopMotor();     // 等待一段时间让机械停稳，再打下一次脉冲     if (now - phaseT0 &gt;= NUDGE_OFF_MS) {       mstate = M_NUDGE_ON;       phaseT0 = now;     }   }</p> <p>// ---- 微调阶段：ON 脉冲 ----   else if (mstate == M_NUDGE_ON) {     // err=1 时脉冲更短，避免过冲，争取落到 err=0     unsigned long onMs = (aerr &lt;= 1) ? NUDGE_ON_MS_FINE : NUDGE_ON_MS_COARSE;</p> <pre><code>bool dirHigh = (err &gt; 0);
setMotor(dirHigh, PWM_NUDGE);

// 脉冲时间到 -&gt; 回到 OFF 等待
if (now - phaseT0 &gt;= onMs) {
