</code></pre> <p>} }</p> <p>// ---------------- GO/STOP 模式与串口命令 ---------------- enum Mode { MODE_STOP, MODE_GO }; Mode mode = MODE_STOP;  // 上电默认 STOP：不跟随温度</p> <p>String cmdLine;</p> <p>// 校准偏移：解决“电机没有绝对0角度”的问题 // sync 时会更新该值，让当前指针对应当前温度的 expectedDeg float calibOffsetDeg = 0.0f;</p> <p>// 预期角度（由温度映射得到）与实际角度（由编码器换算得到） float expectedDeg = 0.0f; float actualDeg   = 0.0f;</p> <p>// GO 模式下把 expectedDeg 换算成目标 count long expectedCountDrive = 0;</p> <p>/   expectedDegToTargetCount(expDeg):   将预期角度 expDeg 转成目标 count（驱动轮编码器）   注意：必须考虑 calibOffsetDeg   模型：   actualDeg = countdegPer + offset   =&gt; count = (expDeg - offset)/degPer */ long expectedDegToTargetCount(float expDeg) {   float pure = wrap180(expDeg - calibOffsetDeg);   return lroundf(pure / degPerDriveCountOnShaft()); }</p> <p>/   handleCommand(s):   处理串口命令：   - s：STOP   - g：GO   - r/l/r5/l5：相对运动（用于微调）   - sync：校准 offset（把当前指针位置认为是正确位置） / void handleCommand(String s) {   s.trim();   s.toLowerCase();</p> <p>if (s == "s") {     mode = MODE_STOP;     mstate = M_IDLE;   // 取消正在执行的运动     stopMotor();     return;   }   if (s == "g") {     mode = MODE_GO;     return;   }</p> <p>// 手动调节：驱动轮转动固定圈数（以 count 精准控制）   if (s == "r")  { motionMoveBy(+ONE_REV_COUNTS); return; }   if (s == "l")  { motionMoveBy(-ONE_REV_COUNTS); return; }   if (s == "r5") { motionMoveBy(+5 * ONE_REV_COUNTS); return; }   if (s == "l5") { motionMoveBy(-5 * ONE_REV_COUNTS); return; }</p> <p>if (s == "sync") {     // 校准逻辑：     // 若 expectedDeg 是“应该指向的位置”，actualDeg 是“当前实际指向的位置”     // 那么它们之间差值 err = expected - actual     // 把这个差值加到 offset 上，就能让“当前实际”被当成“正确”     float err = wrap180(expectedDeg - actualDeg);     calibOffsetDeg = wrap180(calibOffsetDeg + err);     return;   } }</p> <p>// ---------------- Arduino setup/loop ---------------- void setup() {   Serial.begin(9600);</p> <p>// 引脚模式配置   pinMode(PIN_DIR, OUTPUT);   pinMode(PIN_EN, OUTPUT);   pinMode(PIN_ENC_A, INPUT_PULLUP);   pinMode(PIN_ENC_B, INPUT_PULLUP);</p> <p>stopMotor();</p> <p>// I2C 初始化 + 传感器初始化   Wire.begin();   (void)mpl3115a2Init();</p> <p>// 上电时先读一次编码器，计算初始实际角度   long c = readCountDrive();   actualDeg = driveCountToShaftDeg(c, calibOffsetDeg);</p> <p>// 串口提示信息（便于调试/报告）   Serial.println(F("Temp Pointer Ready. Default STOP."));   Serial.println(F("Commands: s(stop) g(go) r l r5 l5 sync"));   Serial.print(F("deg/count(shaft)="));   Serial.println(degPerDriveCountOnShaft(), 6); }</p> <p>void loop() {   // 1) 串口行读取：接收命令（以回车/换行结束）   while (Serial.available()) {     char ch = (char)Serial.read();     if (ch == '\n' || ch == '\r') {       if (cmdLine.length()) {         handleCommand(cmdLine);         cmdLine = "";       }     } else {       cmdLine += ch;       if (cmdLine.length() &gt; 64) cmdLine.remove(0, 32); // 防止字符串过长     }   }</p> <p>// 2) 每 CTRL_MS 执行一次控制逻辑（非阻塞）   static unsigned long lastCtrl = 0;   unsigned long now = millis();   if (now - lastCtrl &gt;= CTRL_MS) {     lastCtrl = now;</p> <pre><code>// 2.1 读取温度，得到 expectedDeg（预期角度）
float tempC = 0.0f;
bool tOk = readTemperatureC(tempC);
if (tOk) expectedDeg = tempToAngleDeg(tempC);

// 2.2 读取编码器，得到 actualDeg（实际角度）
long countDrive = readCountDrive();
actualDeg = driveCountToShaftDeg(countDrive, calibOffsetDeg);

// 2.3 GO 模式：跟随温度
if (mode == MODE_GO) {
  expectedCountDrive = expectedDegToTargetCount(expectedDeg);

  // 只有目标变化时才启动一次新的运动任务
  // 目的：避免每个控制周期都重置状态机造成抖动
  if (expectedCountDrive != targetCountDrive) {
    motionStartTo(expectedCountDrive);
  }
}

// 2.4 STOP 模式：如果没有运动任务，确保电机断电
// 注意：STOP 模式下仍允许 r/l/r5/l5 手动触发 motionStartTo()
if (mode == MODE_STOP &amp;&amp; mstate == M_IDLE) {
  stopMotor();
}

// 2.5 执行运动控制状态机（若有目标则驱动电机）
motionUpdate();

// 3) 每 PRINT_MS 打印一次状态（用于调试/报告记录）
static unsigned long lastPrint = 0;
if (now - lastPrint &gt;= PRINT_MS) {
  lastPrint = now;

  Serial.print(F("T="));
  if (tOk) Serial.print(tempC, 2);
  else Serial.print(F("NaN"));

  Serial.print(F("; expected="));
  Serial.print(expectedDeg, 1);

  Serial.print(F("; actual="));
  Serial.print(actualDeg, 1);

  Serial.print(F("; count="));
  Serial.print(countDrive);

  Serial.print(F("; mode="));
  Serial.println(mode == MODE_GO ? F("GO") : F("STOP"));
}
</code></pre> <p>} }</p> <p>下面按“函数/模块”为单位，把你这份代码里每一个函数（含 inline 小函数）都解释清楚。你写报告时可以直接用这些描述（我用的是偏工程报告风格：目的、输入输出、实现要点）。</p>

